cd /tmp; python3 << 'EOF'
import collections
rows=[]
for line in open('ceb.clean'):
    line=line.rstrip('\n')
    if not line: continue
    lem,form,feat=line.split('\t')
    rows.append((lem,form,feat))

# how often is form==lem
print("total rows:", len(rows))
# lemma prefixes
pref=collections.Counter()
for lem,form,feat in rows:
    for p in ['mag','man','mo','ma']:
        if lem.startswith(p):
            pref[p]+=1; break
    else:
        pref['OTHER']+=1
print("lemma prefixes:", pref)

# For each feature, find longest common substring pattern: does form contain stem (lem minus prefix)?
def stem_of(lem):
    for p in ['mag','man','mo','ma']:
        if lem.startswith(p):
            return p, lem[len(p):]
    return '', lem

feat_prefixchange=collections.defaultdict(collections.Counter)
for lem,form,feat in rows:
    lp,stem=stem_of(lem)
    if form.endswith(stem) and len(stem)>0:
        outpref=form[:len(form)-len(stem)]
        feat_prefixchange[feat][(lp,outpref)]+=1
    else:
        feat_prefixchange[feat][('STEMCHANGE',lem+'->'+form)]+=1

for feat in ['V;NFIN','V;FUT','V;PST','V;PRS','V;PROG;PRS','V;PRF;PST']:
    print("\n===",feat,"===")
    for k,v in feat_prefixchange[feat].most_common(20):
        print(f"  {v:3d}  lemprefix={k[0]!r:8} outprefix={k[1]!r}")
