cd /tmp; python3 << 'EOF'
import collections
rows=[tuple(l.rstrip('\n').split('\t')) for l in open('ceb.clean') if l.strip()]
def stem_of(lem):
    for p in ['mag','man','mo','ma']:
        if lem.startswith(p): return p, lem[len(p):]
    return '', lem
V='aeiou'
for cls in ['ma','mag','man']:
    print(f"\n=== {cls}-verbs ===")
    d=collections.defaultdict(collections.Counter)
    misc=[]
    for lem,form,feat in rows:
        lp,stem=stem_of(lem)
        if lp!=cls: continue
        if form.endswith(stem) and stem:
            op=form[:len(form)-len(stem)]
            vi='V' if stem[0] in V else 'C'
            d[(feat,vi)][op]+=1
        else:
            misc.append((lem,form,feat))
    for k in sorted(d): print(k, dict(d[k]))
    if misc: print(" STEMCHANGE:", misc)
